import { valueToEstree } from "estree-util-value-to-estree";

//#region src/mdx-plugins/mdast-utils.ts
function flattenNode(node) {
	if ("children" in node) return node.children.map((child) => flattenNode(child)).join("");
	if ("value" in node && typeof node.value === "string") return node.value;
	return "";
}
function toMdxExport(name, value) {
	return toMdxExportRaw(name, valueToEstree(value));
}
function toMdxExportRaw(name, expression) {
	return {
		type: "mdxjsEsm",
		value: "",
		data: { estree: {
			type: "Program",
			sourceType: "module",
			body: [{
				type: "ExportNamedDeclaration",
				attributes: [],
				specifiers: [],
				declaration: {
					type: "VariableDeclaration",
					kind: "let",
					declarations: [{
						type: "VariableDeclarator",
						id: {
							type: "Identifier",
							name
						},
						init: expression
					}]
				}
			}]
		} }
	};
}

//#endregion
export { toMdxExport as n, toMdxExportRaw as r, flattenNode as t };